    in-out property <[OverviewUiRow]> overview-module-rows;
    in-out property <string> overview-problems-summary: "Problems: 0";
    in-out property <[OverviewUiRow]> overview-problem-rows;
    in-out property <string> overview-update-heading: "";
    in-out property <string> overview-nexus-update-label: "Nexus Mods";
    in-out property <bool> overview-nexus-update-enabled: false;
    in-out property <string> overview-github-update-label: "GitHub";
    in-out property <bool> overview-github-update-enabled: false;
    in-out property <bool> overview-game-path-enabled: false;
    in-out property <string> overview-downgrade-label: "Downgrade Manager...";
    in-out property <bool> overview-downgrade-enabled: false;
    in-out property <string> overview-downgrade-status: "Deferred until the Downgrade Manager workflow is ported.";
    in-out property <string> overview-archive-patcher-label: "Archive Patcher...";
    in-out property <bool> overview-archive-patcher-enabled: false;
    in-out property <string> overview-archive-patcher-status: "Deferred until the Archive Patcher workflow is ported.";
    in-out property <string> overview-last-action-error: "";

    callback refresh-requested();
    callback open-game-path-requested();
    callback open-nexus-update-requested();
    callback open-github-update-requested();
    callback open-downgrade-manager-requested();
    callback open-archive-patcher-requested();

    background: #202020;

    ScrollView {
        VerticalLayout {
            padding: 20px;
            spacing: 12px;
            alignment: start;

            HorizontalLayout {
                spacing: 12px;
                alignment: start;

                Text {
                    text: "Overview";
                    font-size: 18px;
                    font-weight: 600;
                    color: #f3f3f3;
                    vertical-alignment: center;
                }

                SeverityText {
                    text: root.overview-refresh-message;
                    severity: root.overview-refresh-busy ? "info" : "neutral";
                    font-size: 13px;
                    vertical-alignment: center;
                    wrap: word-wrap;
                }

                Button {
                    text: "Refresh";
                    enabled: !root.overview-refresh-busy;
                    clicked => {
                        root.refresh-requested();
                    }
                }

                Button {
                    text: "Open Game Path";
                    enabled: root.overview-game-path-enabled;
                    clicked => {
                        root.open-game-path-requested();
                    }
                }
            }

            if root.overview-last-action-error != "": Rectangle {
                height: 32px;
                background: #4a2424;
                border-color: #d36b6b;
                border-width: 1px;
                border-radius: 4px;

                Text {
                    text: root.overview-last-action-error;
                    color: #ffd6d6;
                    font-size: 13px;
                    x: 8px;
                    y: 7px;
                    wrap: word-wrap;
                }
            }

            if root.overview-update-heading != "": Rectangle {
                height: 44px;
                background: #24452a;
                border-color: #83c56f;
                border-width: 1px;
                border-radius: 4px;

                HorizontalLayout {
                    padding: 6px;
                    spacing: 8px;
                    alignment: start;

                    Text {
                        text: root.overview-update-heading;
                        color: #eaffdf;
                        font-size: 13px;
                        vertical-alignment: center;
                    }

                    Button {
                        text: root.overview-nexus-update-label;
                        enabled: root.overview-nexus-update-enabled;
                        clicked => {
                            root.open-nexus-update-requested();
                        }
                    }

                    Button {
                        text: root.overview-github-update-label;
                        enabled: root.overview-github-update-enabled;
                        clicked => {
                            root.open-github-update-requested();
                        }
                    }
                }
            }

            OverviewPanel {
                title: "Status";
                rows: root.overview-top-rows;
                label-width: 92px;
            }

            HorizontalLayout {
                spacing: 12px;
                alignment: start;

                OverviewPanel {
                    title: "Binaries (EXE/DLL/BIN)";
                    rows: root.overview-binary-rows;
                    label-width: 112px;
                    action-label: root.overview-downgrade-label;
                    action-enabled: root.overview-downgrade-enabled;
                    action-status: root.overview-downgrade-status;
                    action-requested => {
                        root.open-downgrade-manager-requested();
                    }
                }

                OverviewPanel {
                    title: "Archives (BA2)";
                    rows: root.overview-archive-rows;
                    label-width: 104px;
                    action-label: root.overview-archive-patcher-label;
                    action-enabled: root.overview-archive-patcher-enabled;
                    action-status: root.overview-archive-patcher-status;
                    action-requested => {
                        root.open-archive-patcher-requested();
                    }
                }

                OverviewPanel {
                    title: "Modules (ESM/ESL/ESP)";
                    rows: root.overview-module-rows;
                    label-width: 104px;
                }
            }

            Text {
                text: root.overview-problems-summary;
                color: #f3f3f3;
                font-size: 14px;
                font-weight: 600;
            }

            OverviewPanel {
                title: "Problems";
                rows: root.overview-problem-rows;
                label-width: 132px;
            }
        }
    }
}

fn main() -> Result<(), slint_build::CompileError> {
    slint_build::compile("ui/main.slint")
}

